sql:
SELECT mode_name
FROM sensor_modes
WHERE accel_status = '0';

SELECT mode_name
FROM sensor_modes
WHERE mode_id = 0;

SELECT COUNT(*) AS low_power_mode_count
FROM sensor_modes
WHERE gyro_status = 'Off' AND dmp_status = 'On';

SELECT COUNT(*) AS assign_count
FROM device_mode_logs
WHERE user_id = 1 AND action = 'assign';

SELECT device_id, action, timestamp
FROM device_logs
WHERE action = 'create';

SELECT device_id, assigned_at
FROM device_modes
WHERE status = 'active' AND assigned_at > '2023-10-01 10:00:00';

SELECT COUNT(*) AS active_device_count
FROM device_group_members
WHERE group_id = 1 AND status = 'active';

SELECT sensor_type, setting_value
FROM sensor_mode_settings
WHERE mode_id = 1;

SELECT action
FROM mode_logs
WHERE user_id = 0 AND mode_id = 1 AND timestamp = '2023-10-01 10:05:00';

SELECT COUNT(*) 
FROM mode_logs 
WHERE user_id = 0;

external_knowledge:
Active devices are those with a status of 'active' in the device_group_members table; 
Office Devices refer to devices in the device group with the name 'Office Devices';
Assigned modes are determined by the most recent mode logs.

